    pub fn parse_trade(&self, mut trade: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // aggregate trades
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#compressedaggregate-trades-list
        //
        //     {
        //         "a": 26129,         // Aggregate tradeId
        //         "p": "0.01633102",  // Price
        //         "q": "4.70443515",  // Quantity
        //         "f": 27781,         // First tradeId
        //         "l": 27781,         // Last tradeId
        //         "T": 1498793709153, // Timestamp
        //         "m": true,          // Was the buyer the maker?
        //         "M": true           // Was the trade the best price match?
        //     }
        //
        // recent public trades and old public trades
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#recent-trades-list
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#old-trade-lookup-market_data
        //
        //     {
        //         "id": 28457,
        //         "price": "4.00000100",
        //         "qty": "12.00000000",
        //         "time": 1499865549590,
        //         "isBuyerMaker": true,
        //         "isBestMatch": true
        //     }
        //
        // private trades
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#account-trade-list-user_data
        //
        //     {
        //         "symbol": "BNBBTC",
        //         "id": 28457,
        //         "orderId": 100234,
        //         "price": "4.00000100",
        //         "qty": "12.00000000",
        //         "commission": "10.10000000",
        //         "commissionAsset": "BNB",
        //         "time": 1499865549590,
        //         "isBuyer": true,
        //         "isMaker": false,
        //         "isBestMatch": true
        //     }
        //
        // futures trades
        // https://binance-docs.github.io/apidocs/futures/en/#account-trade-list-user_data
        //
        //     {
        //       "accountId": 20,
        //       "buyer": False,
        //       "commission": "-0.07819010",
        //       "commissionAsset": "USDT",
        //       "counterPartyId": 653,
        //       "id": 698759,
        //       "maker": False,
        //       "orderId": 25851813,
        //       "price": "7819.01",
        //       "qty": "0.002",
        //       "quoteQty": "0.01563",
        //       "realizedPnl": "-0.91539999",
        //       "side": "SELL",
        //       "symbol": "BTCUSDT",
        //       "time": 1569514978020
        //     }
        //     {
        //       "symbol": "BTCUSDT",
        //       "id": 477128891,
        //       "orderId": 13809777875,
        //       "side": "SELL",
        //       "price": "38479.55",
        //       "qty": "0.001",
        //       "realizedPnl": "-0.00009534",
        //       "marginAsset": "USDT",
        //       "quoteQty": "38.47955",
        //       "commission": "-0.00076959",
        //       "commissionAsset": "USDT",
        //       "time": 1612733566708,
        //       "positionSide": "BOTH",
        //       "maker": true,
        //       "buyer": false
        //     }
        //
        // { respType: FULL }
        //
        //     {
        //       "price": "4000.00000000",
        //       "qty": "1.00000000",
        //       "commission": "4.00000000",
        //       "commissionAsset": "USDT",
        //       "tradeId": "1234",
        //     }
        //
        let mut timestamp: Value = self.safe_integer2(trade.clone(), Value::Str("T".to_string()), Value::Str("time".to_string()), &[]);
        let mut price: Value = self.safe_string2(trade.clone(), Value::Str("p".to_string()), Value::Str("price".to_string()), &[]);
        let mut amount: Value = self.safe_string2(trade.clone(), Value::Str("q".to_string()), Value::Str("qty".to_string()), &[]);
        let mut cost: Value = self.safe_string2(trade.clone(), Value::Str("quoteQty".to_string()), Value::Str("baseQty".to_string()), &[]); // inverse futures
        let mut marketId: Value = self.safe_string_k(trade.clone(), "symbol", &[]);
        let mut symbol: Value = self.safe_symbol(marketId.clone(), &[market.clone()]);
        let mut id: Value = self.safe_string2(trade.clone(), Value::Str("t".to_string()), Value::Str("a".to_string()), &[]);
        id = self.safe_string2(trade.clone(), Value::Str("id".to_string()), Value::Str("tradeId".to_string()), &[id.clone()]);
        let mut side: Value = Value::Null;
        let mut orderId: Value = self.safe_string_k(trade.clone(), "orderId", &[]);
        let mut buyerMaker: Value = self.safe_value2(trade.clone(), Value::Str("m".to_string()), Value::Str("isBuyerMaker".to_string()), &[]);
        let mut takerOrMaker: Value = Value::Null;
        if !is_equal(&buyerMaker, &Value::Null) {
            side = ternary(is_true(&buyerMaker), Value::Str("sell".to_string()), Value::Str("buy".to_string())); // this is reversed intentionally
            takerOrMaker = Value::Str("taker".to_string());
        }  else if is_true(&Value::Bool(in_op(&trade, &Value::Str("side".to_string())))) {
            side = self.safe_string_lower(trade.clone(), Value::Str("side".to_string()), &[]);
        }  else {
            if is_true(&Value::Bool(in_op(&trade, &Value::Str("isBuyer".to_string())))) {
                side = ternary(is_true(&get_value(&trade, &Value::Str("isBuyer".to_string()))), Value::Str("buy".to_string()), Value::Str("sell".to_string())); // this is a true side
            }
        }
        let mut fee: Value = Value::Null;
        if is_true(&Value::Bool(in_op(&trade, &Value::Str("commission".to_string())))) {
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("cost".to_string(), self.safe_string_k(trade.clone(), "commission", &[]));
                    m.insert("currency".to_string(), self.safe_currency_code(self.safe_string_k(trade.clone(), "commissionAsset", &[]), &[]));
                m
            });
        }
        if is_true(&Value::Bool(in_op(&trade, &Value::Str("isMaker".to_string())))) {
            takerOrMaker = ternary(is_true(&get_value(&trade, &Value::Str("isMaker".to_string()))), Value::Str("maker".to_string()), Value::Str("taker".to_string()));
        }
        if is_true(&Value::Bool(in_op(&trade, &Value::Str("maker".to_string())))) {
            takerOrMaker = ternary(is_true(&get_value(&trade, &Value::Str("maker".to_string()))), Value::Str("maker".to_string()), Value::Str("taker".to_string()));
        }
        return self.safe_trade(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), trade.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("id".to_string(), id.clone());
        m.insert("order".to_string(), orderId.clone());
        m.insert("type".to_string(), Value::Null);
        m.insert("side".to_string(), side.clone());
        m.insert("takerOrMaker".to_string(), takerOrMaker.clone());
        m.insert("price".to_string(), price.clone());
        m.insert("amount".to_string(), amount.clone());
        m.insert("cost".to_string(), cost.clone());
        m.insert("fee".to_string(), fee.clone());
    m
}), &[market.clone()]);

    Value::Null
}

